"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[40],{7700:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"/2023/11/26/2.5.0","metadata":{"permalink":"/prettier-java/blog/2023/11/26/2.5.0","editUrl":"https://github.com/jhipster/prettier-java/tree/docs/create-website/website/blog/2023-11-26-2.5.0.md","source":"@site/blog/2023-11-26-2.5.0.md","title":"Prettier Java 2.5: Java 21 unnamed patterns and variables preview feature!","description":"This release adds support for the Java 21 preview feature: unnamed patterns and variables (JEP 443)!","date":"2023-11-26T00:00:00.000Z","formattedDate":"November 26, 2023","tags":[],"readingTime":1.05,"hasTruncateMarker":true,"authors":[{"name":"Jordan Kiesel (@jtkiesel)","url":"https://github.com/jtkiesel"}],"frontMatter":{"author":"Jordan Kiesel (@jtkiesel)","authorURL":"https://github.com/jtkiesel","title":"Prettier Java 2.5: Java 21 unnamed patterns and variables preview feature!"},"unlisted":false},"content":"This release adds support for the Java 21 preview feature: unnamed patterns and variables ([JEP 443](https://openjdk.org/jeps/443))!\\n\\n\x3c!-- truncate --\x3e\\n\\n## Highlights\\n\\n### Support Java 21 preview feature: unnamed patterns and variables ([#620](https://github.com/jhipster/prettier-java/pull/620) by [@jtkiesel](https://github.com/jtkiesel))\\n\\nWe\u2019ve added support for the Java 21 preview feature \\"Unnamed Patterns and Variables\\":\\n\\n#### Unnamed pattern variables\\n\\n```java\\n// Example\\nr instanceof Point _\\n```\\n\\n#### Unnamed variables\\n\\n```java\\n// Example\\nint acc = 0;\\nfor (Order _ : orders) {\\n  if (acc < LIMIT) {\\n    // ... acc++ ...\\n  }\\n}\\n```\\n\\n## Other Changes\\n\\n### New entrypoint `lexAndParse` to return both tokens and CST ([#625](https://github.com/jhipster/prettier-java/pull/625) by [@max-schaefer](https://github.com/max-schaefer))\\n\\nProvide an entrypoint that exposes both the CST and the underlying token array.\\n\\n### No longer ignore whole block when `prettier-ignore` at start ([#603](https://github.com/jhipster/prettier-java/pull/603) by [@jtkiesel](https://github.com/jtkiesel))\\n\\nWhen a block begins with `// prettier-ignore`, only the first statement is ignored, rather than the whole block.\\n\\n\x3c!-- prettier-ignore --\x3e\\n```java\\n// Input\\nvoid foo() {\\n  // prettier-ignore\\n  var bar = List.of(\\n    1\\n  );\\n\\n    var baz = 2;\\n}\\n\\n// Prettier Java 2.4\\nvoid foo() {\\n  // prettier-ignore\\n  var bar = List.of(\\n    1\\n  );\\n\\n    var baz = 2;\\n}\\n\\n// Prettier Java 2.5\\nvoid foo() {\\n  // prettier-ignore\\n  var bar = List.of(\\n    1\\n  );\\n\\n  var baz = 2;\\n}\\n```"}]}')}}]);